#!run
// acepad-convert-stack
/* global StackTrace*/
import pNode from "pnode:main";
import * as path from "node:path";
import {loadedModules} from "petit-node";
let _convertRequired;
function convertRequired() {
    if (typeof _convertRequired==="boolean")return _convertRequired;
    const mesg="this is test message";
    try {
        throw new Error(mesg);
    } catch(e) {
        if (e.stack.includes(mesg)) {
            _convertRequired=false;
        } else {
            _convertRequired=true;
        }
    }
}

export const convertStackOLD=(e, force=false)=>{
    if (!force && !convertRequired()) return e;
    if(!e) return e;
    if (typeof e.stack!=="string") return e;
    for (let m of loadedModules()) {
        if (!m.url)continue;
        let i=e.stack.indexOf(m.url);
        if (i<0) continue;
        e.stack=e.stack.substring(0,i)+
        (m.entry?"file://":"")+m.path+e.stack.substring(i+m.url.length);
    }
    e.stack=e.message+"\n"+e.stack;
    return e;
};    

export async function convertStack(e){
    if (typeof StackTrace==="undefined") return e;
    try{
    const trace_offline=await StackTrace.fromError(e,{offline:true});
    const trace=await StackTrace.fromError(e,{
        sourceCache:new Proxy({},{
            get(target,key){
                if (key==="toString"||key==="then"||typeof key==="symbol") return undefined;
                //console.log("sourceCache",key);
                key=key.replace(/^file:\/\//,"");
                return pNode.file(key).text();
            }
        })
    });
    console.log(trace,trace_offline);
    //prt("Source-mapped:");
    let i=0;
    let traceStr=e.toString();
    for (let f of trace) {
        const offline=trace_offline[i];i++;
        if (offline.fileName.match(/^file:/) && !f.fileName.match(/^file:/)) {
            const off=offline.fileName.replace(/^file:\/\//,"");
            f.fileName="file://"+path.join(path.dirname(off), f.fileName);
        } else if (offline.fileName.match(/^blob:/) && !f.fileName.match(/^file:/)) {
            const base=pNode.urlToPath(offline.fileName);
            //console.log("join", base, f.fileName);
            f.fileName="file://"+path.join(path.dirname(base), f.fileName);
        }
        traceStr+="\n"+(f.functionName ?
            `at ${f.functionName} (${f.fileName}:${f.lineNumber}:${f.columnNumber})`:
            `at ${f.fileName}:${f.lineNumber}:${f.columnNumber}`
        );
        //prt(f.fileName+":"+f.lineNumber+":"+f.columnNumber)
    }
    e.stack=traceStr;
    e.trace=trace;
    console.log("stack Converted",e);
    //prt(e.stack);
    //console.error(e);
    }catch(e) {
        console.log("convertStack fail",e);
    }
    return e;
}
